    "@id": "https://app.targetupconsulting.com/blog/articles-actualite-1"
  }
}
</script>

parameters.jsCode:
return $input.all().map(item => {
  const row = item.json;
  let output;

  try {
    // Parse JSON from CONTENU
    output = typeof row.CONTENU === 'string' ? JSON.parse(row.CONTENU) : row.CONTENU;
  } catch (e) {
    return {
      json: {
        error: "Failed to parse JSON",
        details: e.message,
        raw: row.CONTENU
      }
    };
  }

  const title = output.title || "Sans titre";
  let bodyHtml = "";
  let conclusionHtml = "";

  // Prevent double wrapping
  const cleanWrap = (content) => {
    if (!content) return "";
    const trimmed = String(content).trim();
    return trimmed.startsWith('<') ? trimmed : `<p>${trimmed}</p>`;
  };

  // 1. Introduction
  if (output.introduction) {
    bodyHtml += cleanWrap(output.introduction) + "\n";
  }

  // 2. Sections (including conclusion detection)
  if (Array.isArray(output.sections)) {
    output.sections.forEach(section => {
      const heading = section.heading || "";
      const content = section.content || "";
      const isConclusion = heading.toLowerCase().includes("conclusion");

      if (isConclusion) {
        // Store separately to force it at the end
        conclusionHtml += `<h2>Conclusion</h2>\n`;
        conclusionHtml += cleanWrap(content) + "\n";
      } else {
        if (heading) bodyHtml += `<h2>${heading}</h2>\n`;
        if (content) bodyHtml += cleanWrap(content) + "\n";
      }
    });
  }

  // 3. Append conclusion at the end
  bodyHtml += conclusionHtml;

  return {
    json: {
      title: title,
      article_body: bodyHtml,
      metadata: {
        date: row.Date,
        service: row.Service,
        row_id: row.row_number
      }
    }
  };
});

